"use client";
import { useState } from "react";
import { ChromaticAberrationReveal } from "@/components/ui/chromatic-aberration-reveal";

export default function ControlledReveal() {
  const [visible, setVisible] = useState(false);

  return (
    <div className="space-y-4">
      <button
        onClick={() => setVisible((v) => !v)}
        className="rounded-md bg-black px-4 py-2 text-white"
      >
        Toggle reveal
      </button>
      <ChromaticAberrationReveal
        className="h-80 w-full rounded-2xl"
        src="https://images.unsplash.com/photo-1493244040629-496f6d136cc3?auto=format&fit=crop&w=1400&q=80"
        alt="Forest trail"
        trigger="manual"
        isVisible={visible}
      />
    </div>
  );
}
